import{_ as a,c as e,o as s,a as i,a2 as d,a3 as h,a4 as r}from"./chunks/framework.CVNYWbmc.js";const E=JSON.parse('{"title":"分布式温度监测系统——大作业实践笔记","description":"","frontmatter":{"title":"分布式温度监测系统——大作业实践笔记","createTime":"2026-06-08T00:00:00.000Z","categoryName":"STM32","tags":["STM32","FreeRTOS","MQTT","ESP8266","Vue","IoT"],"cover":"/images/temp-monitor-arch.png","summary":"基于 STM32 + FreeRTOS 的分布式温度监测系统，涵盖嵌入式固件、MQTT 通信、Python 后端、Vue 3 监控大屏的开发实践","published":true},"headers":[],"relativePath":"posts/2026/06/temp-monitor-project.md","filePath":"posts/2026/06/temp-monitor-project.md"}'),n={name:"posts/2026/06/temp-monitor-project.md"};function l(o,t,p,c,k,b){return s(),e("div",null,[...t[0]||(t[0]=[i(`<h1 id="分布式温度监测系统——大作业实践笔记" tabindex="-1">分布式温度监测系统——大作业实践笔记 <a class="header-anchor" href="#分布式温度监测系统——大作业实践笔记" aria-label="Permalink to “分布式温度监测系统——大作业实践笔记”">​</a></h1><h2 id="一、项目简介" tabindex="-1">一、项目简介 <a class="header-anchor" href="#一、项目简介" aria-label="Permalink to “一、项目简介”">​</a></h2><p>分布式实时温度监测系统，由多个 STM32 采集节点 + MQTT 云端 + Web 监控大屏组成。</p><table tabindex="0"><thead><tr><th>层级</th><th>技术</th><th>说明</th></tr></thead><tbody><tr><td>MCU 固件</td><td>STM32F103C8T6 + FreeRTOS</td><td>ADC 采集 + MQTT 通信</td></tr><tr><td>WiFi 模块</td><td>ESP8266-01S（AT 指令）</td><td>串口驱动</td></tr><tr><td>后端</td><td>Python FastAPI + paho-mqtt</td><td>MQTT 订阅、WebSocket 推送、REST API</td></tr><tr><td>前端</td><td>Vue 3 + ECharts + Element Plus</td><td>实时温度曲线、设备管理、规则配置</td></tr></tbody></table><h2 id="二、系统架构" tabindex="-1">二、系统架构 <a class="header-anchor" href="#二、系统架构" aria-label="Permalink to “二、系统架构”">​</a></h2><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>┌─────────────────┐    WiFi    ┌──────────────┐    WebSocket    ┌──────────────┐</span></span>
<span class="line"><span>│  STM32 节点 ×N   │──────────►│  MQTT Broker  │◄───────────────│  Vue 3 前端   │</span></span>
<span class="line"><span>│  NTC + ESP8266  │    MQTT    │  Mosquitto   │    paho-mqtt    │  ECharts 大屏 │</span></span>
<span class="line"><span>│  FreeRTOS       │◄──────────│              │◄───────────────│  Pinia Store  │</span></span>
<span class="line"><span>└─────────────────┘           └──────────────┘                 └──────────────┘</span></span>
<span class="line"><span>                                      │ SMTP</span></span>
<span class="line"><span>                                      ▼</span></span>
<span class="line"><span>                               ┌──────────────┐</span></span>
<span class="line"><span>                               │  告警邮件通知   │</span></span>
<span class="line"><span>                               └──────────────┘</span></span></code></pre></div><p><strong>MQTT 主题</strong>：<code>temp/node/{id}</code>（温度上报）、<code>alarm/node/{id}</code>（告警上报）、<code>cmd/node/{id}</code>（远程配置下发）</p><h2 id="三、硬件设计" tabindex="-1">三、硬件设计 <a class="header-anchor" href="#三、硬件设计" aria-label="Permalink to “三、硬件设计”">​</a></h2><table tabindex="0"><thead><tr><th>器件</th><th>型号</th><th>接口</th><th>说明</th></tr></thead><tbody><tr><td>MCU</td><td>STM32F103C8T6</td><td>—</td><td>Cortex-M3, 72MHz, 64KB Flash, 20KB SRAM</td></tr><tr><td>温度传感器</td><td>NTC 10K (B=3950)</td><td>ADC1_CH1 (PA1)</td><td>10K 分压电路</td></tr><tr><td>WiFi 模块</td><td>ESP8266-01S</td><td>USART1 (PA9/PA10)</td><td>115200 波特率</td></tr><tr><td>显示屏</td><td>SSD1306 OLED 0.96&quot;</td><td>软件 I2C (PB6/PB7)</td><td>128×64</td></tr><tr><td>调试串口</td><td>USART2 (PA2/PA3)</td><td>printf 重定向</td><td>115200</td></tr></tbody></table><p>NTC 测温电路：VCC → 10K 分压 → PA1(ADC) → NTC → GND，公式 <code>V_ADC = VCC × R_NTC / (R_series + R_NTC)</code></p><p><strong>实物演示</strong>：</p><p><img src="`+d+`" alt="实物演示"></p><h2 id="四、固件设计" tabindex="-1">四、固件设计 <a class="header-anchor" href="#四、固件设计" aria-label="Permalink to “四、固件设计”">​</a></h2><h3 id="_4-1-freertos-任务划分" tabindex="-1">4.1 FreeRTOS 任务划分 <a class="header-anchor" href="#_4-1-freertos-任务划分" aria-label="Permalink to “4.1 FreeRTOS 任务划分”">​</a></h3><table tabindex="0"><thead><tr><th>任务</th><th>优先级</th><th>周期</th><th>职责</th></tr></thead><tbody><tr><td><code>vTaskSensor</code></td><td>3</td><td>1500ms（<code>vTaskDelayUntil</code>）</td><td>NTC 采集 → OLED 显示 → MQTT 上报 → 告警检查</td></tr><tr><td><code>vTaskUrc</code></td><td>2</td><td>100ms 轮询</td><td>处理 ESP8266 URC 订阅消息</td></tr><tr><td>idle</td><td>0</td><td>自动</td><td>FreeRTOS 空闲任务</td></tr></tbody></table><p>任务间通过互斥锁保护 OLED（软件 I2C 时序敏感）。</p><h3 id="_4-2-ntc-温度计算" tabindex="-1">4.2 NTC 温度计算 <a class="header-anchor" href="#_4-2-ntc-温度计算" aria-label="Permalink to “4.2 NTC 温度计算”">​</a></h3><p>Steinhart-Hart B 参数方程，注意 ADC 溢出保护（传感器断开时 ADC=4095 会导致除零）：</p><div class="language-c"><button title="Copy Code" class="copy"></button><span class="lang">c</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">float</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> resistance </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> SERIES_RESISTANCE </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">*</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> adcValue </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">/</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> (</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">4095.0</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">f</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> -</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> adcValue);</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">float</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> steinhart </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 1.0</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">f</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> /</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> NTC_NOMINAL_TEMPERATURE </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">+</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> logf</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(resistance </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">/</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> NTC_NOMINAL_RESISTANCE) </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">/</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> NTC_B_COEFFICIENT;</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">return</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> (</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">1.0</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">f</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> /</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> steinhart) </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 273.15</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">f</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">;</span></span></code></pre></div><h3 id="_4-3-esp8266-mqtt-通信" tabindex="-1">4.3 ESP8266 MQTT 通信 <a class="header-anchor" href="#_4-3-esp8266-mqtt-通信" aria-label="Permalink to “4.3 ESP8266 MQTT 通信”">​</a></h3><p>使用 <code>AT+MQTTPUBRAW</code> 而非 <code>AT+MQTTPUB</code>——先发长度再发原始字节，避免 JSON 中引号与 AT 指令嵌套冲突。</p><h3 id="_4-4-urc-消息处理" tabindex="-1">4.4 URC 消息处理 <a class="header-anchor" href="#_4-4-urc-消息处理" aria-label="Permalink to “4.4 URC 消息处理”">​</a></h3><p>ESP8266 订阅消息通过 URC（Unsolicited Result Code）主动推送，可能在任意时刻到达。USART1 驱动实现 4 槽 URC 队列，中断中行组装，<code>vTaskUrc</code> 轮询处理。</p><h3 id="_4-5-报警规则引擎" tabindex="-1">4.5 报警规则引擎 <a class="header-anchor" href="#_4-5-报警规则引擎" aria-label="Permalink to “4.5 报警规则引擎”">​</a></h3><p>支持最多 4 条规则，每条包含：<code>type</code>（动作类型）、<code>threshold</code>（阈值）、<code>operator</code>（比较方式）、<code>cooldown_ms</code>（冷却时间）、<code>enabled</code>。</p><p><strong>边云告警分离</strong>：<code>device_alarm</code> 类型 MCU 本地触发 LED（断网也能工作），<code>email_notify</code> 等类型由 MCU 上报、Python 后端负责发送邮件。</p><h3 id="_4-6-远程配置链路" tabindex="-1">4.6 远程配置链路 <a class="header-anchor" href="#_4-6-远程配置链路" aria-label="Permalink to “4.6 远程配置链路”">​</a></h3><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>Vue 表单 → REST API → MQTT publish → ESP8266 URC → vTaskUrc 解析 → AlarmRule_UpdateFromJson → 即时生效</span></span></code></pre></div><p>MCU 端使用 jsmn（零分配 JSON 解析器）+ 自定义点路径访问封装，tokens 数组放 static（约 640 字节），不占堆。</p><h2 id="五、web-后端" tabindex="-1">五、Web 后端 <a class="header-anchor" href="#五、web-后端" aria-label="Permalink to “五、Web 后端”">​</a></h2><h3 id="_5-1-线程安全的-websocket-桥接" tabindex="-1">5.1 线程安全的 WebSocket 桥接 <a class="header-anchor" href="#_5-1-线程安全的-websocket-桥接" aria-label="Permalink to “5.1 线程安全的 WebSocket 桥接”">​</a></h3><p>MQTT 回调在 paho-mqtt 后台线程，WebSocket 推送需在 asyncio 事件循环中执行，使用 <code>asyncio.run_coroutine_threadsafe()</code> 桥接。</p><h3 id="_5-2-设备状态管理" tabindex="-1">5.2 设备状态管理 <a class="header-anchor" href="#_5-2-设备状态管理" aria-label="Permalink to “5.2 设备状态管理”">​</a></h3><p>内存存储，30 秒无数据自动标记离线，每 5 秒检查超时。</p><h3 id="_5-3-rest-api" tabindex="-1">5.3 REST API <a class="header-anchor" href="#_5-3-rest-api" aria-label="Permalink to “5.3 REST API”">​</a></h3><table tabindex="0"><thead><tr><th>接口</th><th>方法</th><th>说明</th></tr></thead><tbody><tr><td><code>/api/nodes</code></td><td>GET</td><td>设备列表及状态</td></tr><tr><td><code>/api/nodes/{id}/rules</code></td><td>GET/PUT/DELETE</td><td>告警规则 CRUD（更新时同步下发到 MCU）</td></tr></tbody></table><h2 id="六、前端监控大屏" tabindex="-1">六、前端监控大屏 <a class="header-anchor" href="#六、前端监控大屏" aria-label="Permalink to “六、前端监控大屏”">​</a></h2><ul><li><code>Dashboard.vue</code>：主监控页面（统计卡片 + 温度曲线 + 设备卡片 + 告警日志）</li><li><code>RuleConfig.vue</code>：告警规则配置页</li><li><code>TempChart.vue</code>：ECharts 多节点实时温度折线图</li><li><code>NodeCard.vue</code>：设备状态卡片（温度颜色编码：蓝&lt;30°C、黄30-40°C、红&gt;40°C）</li></ul><p>Pinia Store 管理设备状态，WebSocket 自动重连（3 秒延迟），每节点保留最近 100 个温度点。</p><p><strong>主页 Dashboard</strong>：</p><p><img src="`+h+'" alt="主页"></p><p><strong>告警规则配置页</strong>：</p><p><img src="'+r+'" alt="规则配置"></p><h2 id="七、踩坑总结" tabindex="-1">七、踩坑总结 <a class="header-anchor" href="#七、踩坑总结" aria-label="Permalink to “七、踩坑总结”">​</a></h2><table tabindex="0"><thead><tr><th>问题</th><th>解决方案</th></tr></thead><tbody><tr><td>AT 指令引号与 JSON 嵌套冲突</td><td>改用 <code>AT+MQTTPUBRAW</code>，先发长度再发原始字节</td></tr><tr><td>URC 消息时序混乱，打断正在发送的指令</td><td>4 槽 URC 队列 + 中断行组装 + 独立任务轮询</td></tr><tr><td>软件 I2C 并发问题（多任务操作 OLED）</td><td>FreeRTOS 互斥锁 + <code>OLED_ShowStringSafe</code> 封装</td></tr><tr><td><code>vTaskDelay</code> 周期不精确</td><td>改用 <code>vTaskDelayUntil</code>，从上次唤醒起算</td></tr><tr><td>20KB SRAM 无法用 cJSON</td><td>使用 jsmn（零分配 tokenizer），tokens 放 static</td></tr></tbody></table><h2 id="八、开发时间线" tabindex="-1">八、开发时间线 <a class="header-anchor" href="#八、开发时间线" aria-label="Permalink to “八、开发时间线”">​</a></h2><table tabindex="0"><thead><tr><th>阶段</th><th>天数</th><th>内容</th></tr></thead><tbody><tr><td>Phase 1 MVP</td><td>~6.5 天</td><td>NTC 采集 → OLED → ESP8266 WiFi → MQTT → Web 基础大屏</td></tr><tr><td>Phase 2 扩展</td><td>~7 天</td><td>FreeRTOS 多任务 → 报警规则引擎 → 远程配置 → 邮件通知</td></tr></tbody></table><h2 id="九、总结" tabindex="-1">九、总结 <a class="header-anchor" href="#九、总结" aria-label="Permalink to “九、总结”">​</a></h2><p>说白了就是 STM32 读温度、WiFi 传上去、网页画个图。技术含量不算高，从 ADC 到浏览器这条线走通了。主要收获是踩了不少坑——AT 指令的引号、串口时序、软件 I2C 抢占，这些都是文档里不会写的。</p>',49)])])}const g=a(n,[["render",l]]);export{E as __pageData,g as default};
